__CPROVER_requires(n == ZOPFLI_NUM_LL)
__CPROVER_requires(__CPROVER_is_fresh(count, n * sizeof(*count)))
__CPROVER_requires(__CPROVER_is_fresh(bitlengths, n * sizeof(*bitlengths)))
/* Counts are bounded so the unsigned sum cannot overflow; this keeps the
   invariant count[k] <= sum, which is what makes every bitlength non-negative.
   The SAT backend needs a constant quantifier bound, so range over the
   compile-time maximum and guard the live prefix with k < n. */
__CPROVER_requires(__CPROVER_forall { size_t k; (k < ZOPFLI_NUM_LL) ==> (k < n ==> count[k] <= 1000) })
__CPROVER_assigns(__CPROVER_object_whole(bitlengths))
/* Each computed bit length is the (clamped) entropy contribution, which is
   non-negative because count[k] <= sum implies log2(sum/count[k]) >= 0. */
__CPROVER_ensures(bitlengths[0] >= 0)
// clang-format on
{
    static const double kInvLog2 = 1.4426950408889; /* 1.0 / log(2.0) */
    unsigned sum = 0;
    unsigned i;
    double log2sum;
    for (i = 0; i < n; ++i)
    {
        sum += count[i];
    }
    log2sum = (sum == 0 ? log(n) : log(sum)) * kInvLog2;
    for (i = 0; i < n; ++i)
    {
        /* When the count of the symbol is 0, but its cost is requested anyway, it
        means the symbol will appear at least once anyway, so give it the cost as if
        its count is 1.*/
        if (count[i] == 0)
            bitlengths[i] = log2sum;
        else
            bitlengths[i] = log2sum - log(count[i]) * kInvLog2;
        /* Depending on compiler and architecture, the above subtraction of two
        floating point numbers may give a negative result very close to zero
        instead of zero (e.g. -5.973954e-17 with gcc 4.1.2 on Ubuntu 11.4). Clamp
        it to zero. These floating point imprecisions do not affect the cost model
        significantly so this is ok. */
        if (bitlengths[i] < 0 && bitlengths[i] > -1e-5)
            bitlengths[i] = 0;
        assert(bitlengths[i] >= 0);
    }
}

/* Calculates the entropy of the statistics */
static void CalculateStatistics(SymbolStats *stats)
{
    ZopfliCalculateEntropy(stats->litlens, ZOPFLI_NUM_LL, stats->ll_symbols);
    ZopfliCalculateEntropy(stats->dists, ZOPFLI_NUM_D, stats->d_symbols);
}

/* Appends the symbol statistics from the store. */
static void GetStatistics(const ZopfliLZ77Store *store, SymbolStats *stats)
{
    size_t i;
    for (i = 0; i < store->size; i++)
    {
        if (store->dists[i] == 0)
        {
            stats->litlens[store->litlens[i]]++;
        }
        else
        {
            stats->litlens[ZopfliGetLengthSymbol(store->litlens[i])]++;
            stats->dists[ZopfliGetDistSymbol(store->dists[i])]++;
        }
    }
    stats->litlens[256] = 1; /* End symbol. */

    CalculateStatistics(stats);

